<div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h1 class="h4">New Inspection Template</h1><form method="post" action="/portal/inspection-templates" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input name="name" class="form-control" required></div><div class="col-12"><label class="form-label">Applies To</label><select name="entity_type" class="form-select"><option>job</option><option>vehicle</option><option>property</option><option>equipment</option></select></div><div class="col-12"><label class="form-label">Description</label><textarea name="description" class="form-control"></textarea></div><div class="col-12 form-check ms-2"><input type="checkbox" class="form-check-input" name="active" checked id="active"><label for="active" class="form-check-label">Active</label></div><div class="col-12"><button class="btn btn-primary w-100">Create Template</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="card-header"><h2 class="h5 mb-0">Templates</h2></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Name</th><th>Type</th><th>Items</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($templates as $t):?><tr><td><?=e($t['name'])?></td><td><?=e($t['entity_type'])?></td><td><?=$t['item_count']?></td><td><?=$t['active']?'Active':'Inactive'?></td><td><a class="btn btn-sm btn-outline-primary" href="/portal/inspection-templates/<?=$t['id']?>">Configure</a></td></tr><?php endforeach?></tbody></table></div></div></div></div>
